// Extract skill name and arguments from request body
const body = $input.item.json.body;
const skillName = body.skill;
const args = body.args || {};

// Map skill names to commands
const skillCommands = {
  'system_status': 'python3 /home/openclaw/aureon-skills/system_status.py',
  'read_logs': `python3 /home/openclaw/aureon-skills/read_logs.py ${args.service || 'openclaw'} ${args.lines || 50}`,
  'deploy_app': `python3 /home/openclaw/aureon-skills/deploy_app.py ${args.environment || 'staging'}`,
  'n8n_trigger': `python3 /home/openclaw/aureon-skills/n8n_trigger.py ${args.workflow}`,
  'squad_activation': `python3 /home/openclaw/aureon-skills/squad_activation.py ${args.squad || 'sales'}`,
  'send_whatsapp': `python3 /home/openclaw/aureon-skills/send_whatsapp.py '${args.recipient}' '${args.message}'`,
  'execute_command': `python3 /home/openclaw/aureon-skills/execute_command.py '${args.command}' ${args.confirmed ? '--confirmed' : ''}`
};

const command = skillCommands[skillName];

if (!command) {
  throw new Error(`Unknown skill: ${skillName}`);
}

return {
  json: {
    command: command,
    skill: skillName,
    args: args
  }
};

// Parse JSON output from skill
const stdout = $input.item.json.stdout;
let result;

try {
  result = JSON.parse(stdout);
} catch (e) {
  // If not JSON, return raw output
  result = {
    success: true,
    output: stdout,
    raw: true
  };
}

return {
  json: {
    skill: $node['Build SSH Command'].json.skill,
    result: result,
    executedAt: new Date().toISOString()
  }
};

// Handle errors
const error = $input.item.json;

return {
  json: {
    success: false,
    error: error.message || 'Unknown error',
    skill: $node['Build SSH Command'].json.skill,
    executedAt: new Date().toISOString()
  }
};
